#!/usr/bin/env python"""DCT Image Averaging DemoThis script demonstrates that averaging images in spatial domainis equivalent to averaging them in DCT domain.DCT = Discrete Cosine TransformSpatial domain:    pixel intensity imageDCT domain:    cosine frequency coefficientsBecause DCT is linear:    average(images) == inverse_DCT(average(DCT(images)))"""import cv2import numpy as npimport matplotlib.pyplot as pltfrom scipy.fftpack import dct, idctfrom os import listdirimport os# ---------------------------------------------------# STEP 1: Set image folder path# ---------------------------------------------------image_dir = "../data/noisy_images/25_sigma/"# ---------------------------------------------------# STEP 2: Load all images in the folder# ---------------------------------------------------filenames = listdir(image_dir)filenames.sort()imgs = []for filename in filenames:    path = os.path.join(image_dir, filename)    img = cv2.imread(path, 0)    if img is None:        print("Could not load:", path)        continue    imgs.append(img.astype(np.float32))if len(imgs) < 2:    raise ValueError("Need at least 2 images for averaging.")# ---------------------------------------------------# STEP 3: Prepare empty images for averaging# ---------------------------------------------------height, width = imgs[0].shapeavg_img = np.zeros((height, width), np.float32)dct_avg_img = np.zeros((height, width), np.float32)# ---------------------------------------------------# STEP 4: Average images in spatial domain and DCT domain# ---------------------------------------------------for i in range(len(imgs)):    # Running average in normal image space    avg_img = cv2.addWeighted(        avg_img,        i / (i + 1.0),        imgs[i],        1 / (i + 1.0),        0    )    # Running average in DCT frequency space    dct_img = dct(dct(imgs[i].T, norm="ortho").T, norm="ortho")    dct_avg_img = cv2.addWeighted(        dct_avg_img,        i / (i + 1.0),        dct_img,        1 / (i + 1.0),        0    )# ---------------------------------------------------# STEP 5: Convert averaged DCT back to image space# ---------------------------------------------------reverse_img = idct(idct(dct_avg_img.T, norm="ortho").T, norm="ortho")# ---------------------------------------------------# STEP 6: Display results# ---------------------------------------------------fig = plt.figure(figsize=(10, 10))ax1 = fig.add_subplot(2, 2, 1)ax1.imshow(imgs[0], cmap="gray")ax1.set_title("Input Image 1")ax1.axis("off")ax2 = fig.add_subplot(2, 2, 2)ax2.imshow(imgs[1], cmap="gray")ax2.set_title("Input Image 2")ax2.axis("off")ax3 = fig.add_subplot(2, 2, 3)ax3.imshow(avg_img, cmap="gray")ax3.set_title("Average in Image Space")ax3.axis("off")ax4 = fig.add_subplot(2, 2, 4)ax4.imshow(reverse_img, cmap="gray")ax4.set_title("Average in DCT Space, then IDCT")ax4.axis("off")plt.tight_layout()plt.show()